import{_ as e,o as t,c as b,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"魔女庭院技艺组","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/魔女庭院技艺组.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/魔女庭院技艺组.md"}'),s={name:"4.资源分区/6.技艺及称号/通用及综合类/魔女庭院技艺组.md"};function o(d,a,_,l,i,c){return t(),b("div",null,[...a[0]||(a[0]=[r("h1",{id:"魔女庭院技艺组",tabindex:"-1"},[p("魔女庭院技艺组 "),r("a",{class:"header-anchor",href:"#魔女庭院技艺组","aria-label":'Permalink to "魔女庭院技艺组"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌034")])])],-1),n('<h1 id="魔女庭院技艺组-1" tabindex="-1">魔女庭院技艺组 <a class="header-anchor" href="#魔女庭院技艺组-1" aria-label="Permalink to &quot;魔女庭院技艺组&quot;">​</a></h1><p>魔女庭院技艺组<br> 本质：魔幻本质<br> 技艺组<br> 在很久很久以前，魔女们于无尽的黑暗中诞生。<br> 魔女们既不知道自己为何而生，也不知道将来该做何事。<br> 直到有一天，梦之魔女降临到她们的世界。<br> 这位梦之魔女可以在梦中打造属于自己的世界。<br> 魔女们对此感到新奇无比，纷纷拜托她让自己住进那个世界。<br> 梦之魔女欣然邀请了众人，于是，那里开始被魔女们称之为“庭院”。</p><p>茜尔<br> D+500<br> 用线之魔女织的网。<br> 每个被你攻击命中的单位将跟之间产生一根魔法的丝线，被丝线标记的单位在被丝线缠绕的回合结束时受到等同于身上丝线数量的纯能量伤害，然后身上的丝线数量归零。<br> 你对被你丝线标记的单位将具有你留下的魔法纺丝针，魔法纺丝针将存在一个场景，在此期间你侦测标记的单位时，你的视觉感知能力视为强感知方式。</p><p>菲奥娜<br> D+500<br> 用花之魔女酿的露珠<br> 你的走路飘飘晃晃，行走路上产生花瓣，你的移速增加15米，<br> 你在移动后，花瓣使你下一个进行的风度检定额外获得1点附加成功。</p><p>阿比盖尔<br> D+500<br> 用南瓜魔女扎根的土壤<br> 你获得黑暗派系D级的法术派系造诣，选择一把镰刀武器，你现在可以将其作为法器进行施法，它的武器伤害会被永久性的转换为等量的法术强度，将其作为法器进行施法时，武器上原本具有的特性在符合条件的情况下仍然可以生效选定的武器一经选择不可更换。<br> （例：武器原本具有【进行攻击时可同时攻击触及范围内的敌方单位】特性，则你使用其进行施法时也可以同时攻击触及范围内的单位）<br> 进入战斗的每回合结束时，一只由能量组成的黑暗乌鸦将生成在你的周围，每只乌鸦在你释放黑暗派系的法术进行攻击时额外给于2点破魔，乌鸦存在上限为4只。战斗结束时乌鸦消失。</p><p>丽兹&amp;贝莉<br> D+500<br> 用血之魔女吞噬的肉块<br> 你驱使的召唤物或随从的攻击具有【吸血1】，以此吸血效果触发的过量治疗由轮回者本人生效。<br> 你驱使的召唤物或随从被你的契约强化，具有基于天生防御的1点附加成功。</p><p>克洛伊<br> C+1000<br> 用蜡之魔女点亮的火花<br> 你的施法或者远程攻击带有1点不可豁免的环境来源的燃烧点数<br> 每回合被你远程攻击或者施法攻击命中的第一个单位（如果为复数则自选一个）直到下回合身体被蜡制作的蛛网给缠住，移速-20米。</p><p>纳哈特拉<br> ？？？<br> 此刻，以众魔女之名，茶会启幕。<br> ...<br> 留些故事，让星星低语轻诉吧。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const m=e(s,[["render",o]]);export{f as __pageData,m as default};
